import Testing
import Foundation

@testable import Jora

class ResolveCountryUseCaseTests {
    let countryManager = MockCountryManager()

    lazy var sut = DefaultResolveCountryUseCase(countryManager: countryManager)

    init() {
        // Clear UserDefaults before each test
        UserDefaults.standard.removeObject(forKey: User.UserDefaultsKey.defaultCountry.stateDefaultsKey)
    }

    @Test("Returns saved country when valid code exists in UserDefaults")
    func returnsSavedCountryWhenValidCode() {
        UserDefaults.standard.set("IN", forKey: User.UserDefaultsKey.defaultCountry.stateDefaultsKey)

        let result = sut()

        #expect(result.code == "IN")
    }

    @Test("Returns default country when no saved code exists")
    func returnsDefaultCountryWhenNoSavedCode() {
        // UserDefaults is cleared in init

        let result = sut()

        #expect(result.code == "RU") // MockCountryManager.Russia is default
    }

    @Test("Returns default country when saved code is invalid")
    func returnsDefaultCountryWhenInvalidCode() {
        UserDefaults.standard.set("INVALID", forKey: User.UserDefaultsKey.defaultCountry.stateDefaultsKey)

        let result = sut()

        #expect(result.code == "RU") // MockCountryManager.Russia is default
    }

    @Test("Returns default country when saved code is empty")
    func returnsDefaultCountryWhenEmptyCode() {
        UserDefaults.standard.set("", forKey: User.UserDefaultsKey.defaultCountry.stateDefaultsKey)

        let result = sut()

        #expect(result.code == "RU") // MockCountryManager.Russia is default
    }

    deinit {
        // Clean up after tests
        UserDefaults.standard.removeObject(forKey: User.UserDefaultsKey.defaultCountry.stateDefaultsKey)
    }
}

