import Testing
import Foundation

@testable import Jora

struct UserIntegrationTests {

    @Test("User.current static instance maintains backward compatibility")
    func userCurrentMaintainsBackwardCompatibility() {
        let staticUser = User.current

        // Should not crash
        let country = staticUser.selectedCountry
        #expect(country.code.isEmpty == false)

        // Should be able to set country
        let originalCountry = staticUser.selectedCountry
        staticUser.selectedCountry = Countries.Germany

        // Should be able to logout without issues
        staticUser.logout()
        #expect(staticUser.isLoggedIn == false)

        // Clean up by restoring original country
        staticUser.selectedCountry = originalCountry
    }

    @Test("Dependency injection works with real DIService resolution") 
    func dependencyInjectionWorksWithRealDIServiceResolution() {
        // This tests that DIService.resolve() returns a working ResolveCountryUseCase
        let user = User() // Uses default DIService.resolve()

        // Should not crash and should return a valid country
        let country = user.selectedCountry
        #expect(country.code.isEmpty == false)
        #expect(country.domain.isEmpty == false)
    }

    @Test("ResolveCountryUseCase integration with real CountryManager")
    func resolveCountryUseCaseIntegrationWithRealCountryManager() {
        // Test the full chain: User -> ResolveCountryUseCase -> CountryManager
        let countryManager = MockCountryManager()
        let resolveCountry = DefaultResolveCountryUseCase(countryManager: countryManager)
        let user = User(resolveCountry: resolveCountry)

        let testKey = User.UserDefaultsKey.defaultCountry.stateDefaultsKey

        // Clear UserDefaults
        UserDefaults.standard.removeObject(forKey: testKey)

        // Should return default country when nothing is saved
        let defaultCountry = user.selectedCountry
        #expect(defaultCountry.code == "RU") // MockCountryManager default

        // Set a country and verify it persists
        user.selectedCountry = Countries.Australia
        let savedCountry = user.selectedCountry  
        #expect(savedCountry.code == "AU")

        // Verify UserDefaults was updated
        let savedCode = UserDefaults.standard.string(forKey: testKey)
        #expect(savedCode == "AU")

        // Create new user instance and verify it loads saved country
        let newUser = User(resolveCountry: resolveCountry)
        let loadedCountry = newUser.selectedCountry
        #expect(loadedCountry.code == "AU")

        // Clean up
        UserDefaults.standard.removeObject(forKey: testKey)
    }

    @Test("User functionality remains intact after dependency injection refactoring")
    func userFunctionalityRemainsIntactAfterRefactoring() {
        let user = User()

        // Test core User functionality that should not be affected
        #expect(user.isLoggedIn == false)
        #expect(user.userId == nil)
        #expect(user.searchCount >= 0)
        #expect(user.hasLaunched == false || user.hasLaunched == true) // Can be either

        // Test that we can set credentials without issues
        let credentials = OAuth(
            refreshToken: "test_refresh",
            accessToken: "test_access",
            tokenType: "bearer",
            expiresIn: 3600,
            newUser: false,
            createdAt: Date.now.timeIntervalSince1970,
            userId: "test_user_id"
        )

        user.credentials = credentials
        #expect(user.isLoggedIn == true)
        #expect(user.userId == "test_user_id")

        // Test logout
        user.logout()
        #expect(user.isLoggedIn == false)
        #expect(user.userId == nil)
    }

    @Test("WithUser protocol extension works with refactored User")
    func withUserProtocolExtensionWorks() {
        struct TestClass: WithUser {
            let user: User
        }

        let mockResolveCountry = MockResolveCountryUseCase()
        mockResolveCountry.stubbedCountry = Countries.Singapore

        let testUser = User(resolveCountry: mockResolveCountry)
        let testObject = TestClass(user: testUser)

        // The WithUser extension should provide selectedCountry
        #expect(testObject.selectedCountry.code == "SG")
    }
}
